今天把 Selector、Photoshop、FCKEditor 三个重点的控件都搞定了，贴几张图炫耀一下~ 

代码： 
//1. 生成并获得一个新的EntityView控件，也就是记录内容编辑控件
   $rEntityView =& $this->createControl('edit', 'EntityView');
//2. 定义一个只含有特定Key记录的数据表
   $table = new Table('base_news', 'Entity', '*', DFieldKey.'='.$mKey );
//3. 定义一个外键所对应的数据表
   $table_category = new Table('base_news_category');
//4. 设置外键，本地的category字段对应外表的name字段
   $table->setForeignField('category', $table_category, 'name');
//5. 将数据表设置给EntityView控件
   $rEntityView->setTable( $table );
//6. 设置EntityView控件的标题
   $rEntityView->setCaption('土国新闻具体内容');
//7. 设置第一行(行?Columns? 这个名字好像好改一下……从ListView抄过来的……)，id，第四个参数true表示readonly
   $rEntityView->addShowColumns('id', 'id', DEntityViewTypeInt, true);
//8. 设置第二行，是外键，所以字段名比较长 本表字段/外键表/外键表字段 ，第五个参数true表示是外键
   $rEntityView->addShowColumns('category/base_news_category/name', '类别', DEntityViewTypeString ,false, true);
//9. 设置其它行，第三个参数宏是代表这一行的类型
   $rEntityView->addShowColumns('title', '标题', DEntityViewTypeString);
   $rEntityView->addShowColumns('isshow', '是否显示', DEntityViewTypeCheck);
   $rEntityView->addShowColumns('content', '正文', DEntityViewTypeText);
   $rEntityView->addShowColumns('pic', '照片', DEntityViewTypePic);
   $rEntityView->addShowColumns('pic2', '照片2', DEntityViewTypePic);

这样就好了，剩下的事情就交给调度器来调用控件的show了，他就出现了~


